import base64
import requests
from lxml import etree
from xml.etree.ElementTree import Element, SubElement, tostring

class SAMLServiceProvider:
    def __init__(self, destination_url):
        self.destination_url = destination_url

    def create_authn_request(self, user_id, relay_state):
        # Prevent SAML XML injection by escaping user input
        user_id = self.escape_xml(user_id)
        relay_state = self.escape_xml(relay_state)

        # Create SAML AuthnRequest XML
        root = Element('s:AuthnRequest', {
            'xmlns:s': 'urn:oasis:names:tc:SAML:2.0:protocol',
            'ID': self.generate_id(),
            'Version': '2.0',
            'IssueInstant': self.get_current_time(),
            'Destination': self.destination_url,
            'AssertionConsumerServiceURL': 'https://your-service-provider.com/acs',
            'ProtocolBinding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST'
        })

        issuer = SubElement(root, 's:Issuer')
        issuer.text = 'https://your-service-provider.com'

        name_id_policy = SubElement(root, 's:NameIDPolicy', {
            'Format': 'urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified',
            'AllowCreate': 'true'
        })

        # Add user information as an attribute (if needed)
        user_info = SubElement(root, 's:Subject')
        name_id = SubElement(user_info, 's:NameID')
        name_id.text = user_id

        # Convert XML to string
        saml_request = tostring(root, encoding='utf-8', xml_declaration=True)
        encoded_request = base64.b64encode(saml_request).decode('utf-8')

        return encoded_request

    def send_authn_request(self, user_id, relay_state):
        saml_request = self.create_authn_request(user_id, relay_state)
        response = requests.post(self.destination_url, data={'SAMLRequest': saml_request, 'RelayState': relay_state})
        return response

    @staticmethod
    def escape_xml(value):
        return etree.CDATA(value)

    @staticmethod
    def generate_id():
        import uuid
        return f"_{uuid.uuid4()}"

    @staticmethod
    def get_current_time():
        from datetime import datetime
        return datetime.utcnow().isoformat() + 'Z'

